import{_ as i,o as a,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Predictive Modeling (PREM)","description":"","frontmatter":{"title":"Predictive Modeling (PREM)","slug":"predictive-modeling"},"headers":[],"relativePath":"marketer-hub/predictive-modeling.md","filePath":"marketer-hub/predictive-modeling.md"}'),r={name:"marketer-hub/predictive-modeling.md"};function n(s,e,l,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Predictive Modeling (PREM) is a probabilistic recognition system, that cross-references past user interactions across the Branch Link Graph, to more accurately attribute conversion events. PREM analyzes patterns in device-level event metadata to uncover the most likely connection only used where allowed under platform policies These matches are a significant improvement over point-in-time Fingerprinting, and extremely reliable for most use cases, but should not be relied upon for authentication or other critical failure use cases. The probabilistic estimation is based on the uniqueness of a combination of device characteristics, the presence of web cookies, and the number of devices seen frequenting the same IP address over time.</p><h3 id="benefits-of-using-prem" tabindex="-1">Benefits of using PREM <a class="header-anchor" href="#benefits-of-using-prem" aria-label="Permalink to &quot;Benefits of using PREM&quot;">​</a></h3><ul><li>User-level metrics</li><li>Visibility of ongoing app activity</li><li>Support for different accounting and value-based methods like top-of-the-funnel assists, re-engagement campaigns, and MTA</li><li>Real-time optimization for continuous campaign optimization</li></ul><h2 id="how-does-prem-work" tabindex="-1">How does PREM work? <a class="header-anchor" href="#how-does-prem-work" aria-label="Permalink to &quot;How does PREM work?&quot;">​</a></h2><ol><li><p>User clicks on any Branch Link</p></li><li><p>PREM observes key traffic characteristics like:</p><ul><li>Device IP</li><li>Timestamp</li><li>OS</li></ul></li><li><p>Branch attempts to match that device that has completed a conversion to an upstream advertisement click.</p></li><li><p>PREM estimates the probability that the device is the same as a previously seen device based on the uniqueness of a combination of device characteristics, presence of web cookies, and number of devices seen frequenting the same IP address over time)</p></li></ol><h2 id="where-is-prem-used" tabindex="-1">Where is PREM used? <a class="header-anchor" href="#where-is-prem-used" aria-label="Permalink to &quot;Where is PREM used?&quot;">​</a></h2><p>By default, PREM is used in the follow scenarios:</p><h3 id="ios" tabindex="-1">iOS: <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS:&quot;">​</a></h3><ol><li>To attribute conversions to paid channels ONLY if a user has opted in to Apple&#39;s AppTrackingTransparency modal</li><li>To attribute conversions to non-paid channels</li></ol><h3 id="android" tabindex="-1">Android: <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android:&quot;">​</a></h3><p>In all scenarios</p>',12)])])}const m=i(r,[["render",n]]);export{u as __pageData,m as default};
